VALUES
  ('social-worker-moex-00601', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關結案工作的敘述，下列何者正確？', '["當案主因為工作轉業或其他因素要結束服務，會讓社會工作者心生罪惡感", "非計畫性結案是案主主動退出或是社會工作者離職所形成的專業關係結束", "實習進行的個案服務因為期程限制，所以不需要再特別提醒結案時間", "結案工作最優先的是讓案主能夠計畫未來，而不是檢視已經有的改變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00602', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者運用資源時，事先經過資源預估（assessment）才提供個案相關服務，使資源的運用符 合效益與效率。這樣的資源運用方式屬於那一種理論取向？', '["差別潛力的功能論", "優先順序的行動論", "教育動員的過程論", "系統運用的結合論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00603', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會工作會談的敘述，下列何者正確？', '["與案主會談時，要避免過多的社交性會談", "了解案主需求遠比同理溝通來得重要許多", "社會工作者應該以社會控制者角色來與非自願案主會談", "運用E會談可以讓經濟弱勢者也有相同的服務可及性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00604', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是社會工作倫理守則的限制？', '["倫理守則的修訂常常趕不上社會情境變化", "倫理守則通常只能針對一般狀況或通例來規範", "倫理守則的實踐常是單純步驟或直接過程", "倫理守則之間可能產生相互矛盾之處"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00605', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關效益主義的敘述，下列何者正確？', '["全體善果效益主義是指最適當的行動是能增進全體的和整體的好處", "規則效益主義是指行動的正確性要視那個特定行動能產生的好處為何而定", "行動效益主義是指最適當的行動是能有越多人能分享到這些好處越好", "效益主義是指只要能在過程中遵守所有的義務，就會獲得最大的效益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00606', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關案主自我決定的敘述，下列何者正確？', '["即使案主的選擇不適當，也會找到保護自己的方法", "案主自我決定的權利並不容許自我傷害或傷害別人", "社會工作者無法滿足案主想望的需求時，只能讓案主決定", "當案主為未成年時，社會工作者可以代替案主做決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00607', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作定義所涵括的意涵，下列何者錯誤？', '["團體工作者引導成員互動，促使建立關係，以獲得良好的成長經驗", "團體工作者所服務的團體，包括處遇性團體（treatmentgroup）和任務性團體（taskgroup）", "團體和其所贊助的機構彼此會相互影響", "團體工作者針對「目標導向的活動」設計和運用，其注意力只放在個別成員身上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00608', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關不同類型任務性團體的領導，下列何者正確？', '["「工作小組」的領導者是由自然產生的領導者擔任", "「代表會議」的領導者是由發起機構所任命的代表擔任", "「治療會議」的領導者是由贊助機構委派", "「聯盟」的領導者是由被指派者擔任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00609', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會團體工作、團體輔導、團體諮商、團體心理治療的比較，下列何者錯誤？', '["社會團體工作主要服務對象是一般人或弱勢族群", "團體諮商目標是增進與獲得知識與資料，建立正確之觀念、認知及健康的態度與行為", "團體輔導的助人關係，主要是強調對當事人的觀念、認知、行為、態度等建立導引關係", "團體心理治療的處遇焦點是意識及潛意識層面的思想、情緒和行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00610', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '假使成員A有某種行為出現，而成員B予以正向的回應，會使A繼續此種行為；同樣的，假使 團體工作者的某項特別行為獲得團體成員負向的回饋，工作者未來將會減少此種行為。請問前述 情況可以用下列何者解釋？', '["認知行為理論", "社會學習理論", "操作制約", "古典制約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "9624554dfd5e", "answer_pdf_sha1": "0567489b9e64", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
